// Urban Skyline — Deluxe Edition
// Adapted from GenerativeArtGallery / artwork11
// Parallax layers, water reflection, twinkling stars, crescent moon,
// drifting clouds, wing-flapping birds, window flicker, pulsing beacons,
// neon signs, rain, fog, ripple shimmer, 7 curated palettes

let us = { bg:[], fg:[], stars:[], clouds:[], birds:[], prevD:'', prevT:'' };

let usPal = {
  twilight: { s1:[268,55,42], s2:[240,40,18], bl:[240,18,38], bk:[240,12,25], wn:[42,82,96],  wt:[230,40,18], moon:1, star:1, rain:0 },
  neon:     { s1:[260,85,14], s2:[240,70,6],  bl:[260,30,15], bk:[260,20,10], wn:[300,92,100], wt:[270,50,8],  moon:0, star:0, rain:0 },
  dawn:     { s1:[15,65,90],  s2:[30,40,75],  bl:[20,28,36],  bk:[20,18,24],  wn:[48,72,96],   wt:[20,30,42],  moon:0, star:0, rain:0 },
  golden:   { s1:[38,75,92],  s2:[25,50,72],  bl:[25,35,30],  bk:[25,25,20],  wn:[50,82,100],  wt:[30,40,38],  moon:0, star:0, rain:0 },
  midnight: { s1:[225,50,12], s2:[230,40,5],  bl:[220,18,18], bk:[220,12,12], wn:[200,50,78],  wt:[220,35,8],  moon:1, star:1, rain:0 },
  rainy:    { s1:[210,20,45], s2:[200,15,30], bl:[200,12,32], bk:[200,8,20],  wn:[45,55,82],   wt:[205,18,22], moon:0, star:0, rain:1 },
  sunset:   { s1:[10,80,95],  s2:[340,60,55], bl:[350,25,28], bk:[350,18,18], wn:[40,75,95],   wt:[350,35,28], moon:0, star:0, rain:0 }
};

function usGen(dens, isBg) {
  let bs = [], sp = dens === 'sparse' ? 62 : dens === 'medium' ? 40 : 26;
  let hm = isBg ? 0.5 : 1, x = -sp;
  while (x < 420) {
    let w = sp * (0.55 + Math.random() * 0.85);
    let h = (42 + Math.random() * Math.random() * (isBg ? 150 : 290)) * hm;
    let wc = Math.max(1, Math.floor(w / (isBg ? 22 : 16)));
    let wr = Math.max(1, Math.floor(h / (isBg ? 26 : 19)));
    let wins = [];
    for (let r = 0; r < wr; r++)
      for (let c = 0; c < wc; c++)
        wins.push({ r:r, c:c, lit: Math.random() > 0.22 });
    let rt = Math.random();
    bs.push({
      x:x, w:w, h:h, wins:wins, wc:wc, wr:wr,
      ant: !isBg && Math.random() > 0.5,
      roof: rt < 0.58 ? 0 : rt < 0.8 ? 1 : 2,
      stepH: 7 + Math.random() * 14,
      stepW: w * (0.35 + Math.random() * 0.3),
      nH: Math.random() * 360,
      nW: 8 + Math.random() * 18,
      nHt: 4 + Math.random() * 7,
      nY: Math.random() * 0.3
    });
    x += w + Math.random() * 5;
  }
  return bs;
}

p.setup = function() {
  p.createCanvas(400, 500);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  us.bg = usGen('medium', true);
  us.fg = usGen('medium', false);
  for (let i = 0; i < 85; i++)
    us.stars.push({ x: Math.random()*400, y: Math.random()*265, s: 0.5+Math.random()*2.5, ph: Math.random()*6.28, sp: 0.02+Math.random()*0.04 });
  for (let i = 0; i < 4; i++)
    us.clouds.push({ x: Math.random()*500-50, y: 22+Math.random()*110, w: 80+Math.random()*130, h: 18+Math.random()*28, sp: 0.12+Math.random()*0.28 });
  for (let i = 0; i < 6; i++)
    us.birds.push({ x: Math.random()*400, y: 20+Math.random()*85, vx: 0.5+Math.random()*1.6, sz: 1+Math.random()*2.2 });
};

function usDrawB(blds, gY, bc, wc, det, t, neon) {
  blds.forEach(function(b) {
    let by = gY - b.h;
    p.noStroke();
    p.fill(bc[0], bc[1], bc[2], 100);
    p.rect(b.x, by, b.w, b.h);
    if (det !== 'minimal') {
      if (b.roof === 1) p.rect(b.x + (b.w - b.stepW) / 2, by - b.stepH, b.stepW, b.stepH);
      else if (b.roof === 2) p.triangle(b.x, by, b.x + b.w, by, b.x + b.w / 2, by - b.stepH);
    }
    let wW = b.w / (b.wc + 1), wH = b.h / (b.wr + 1);
    b.wins.forEach(function(w) {
      let wx = b.x + (w.c + 0.5) * wW;
      let wy = by + (w.r + 0.5) * wH;
      if (w.lit) p.fill(wc[0], wc[1], wc[2], 92);
      else p.fill(bc[0], bc[1] * 0.3, bc[2] * 0.5, 62);
      p.rect(wx, wy, wW * 0.48, wH * 0.48);
    });
    if (b.ant && det !== 'minimal') {
      let ax = b.x + b.w * 0.5;
      p.stroke(bc[0], bc[1] + 10, bc[2] + 22, 65);
      p.strokeWeight(1.5);
      p.line(ax, by, ax, by - 24);
      if (det === 'detailed') {
        let ba = (Math.sin(t * 0.08) * 0.5 + 0.5) * 80 + 15;
        p.noStroke();
        p.fill(0, 85, 95, ba);
        p.ellipse(ax, by - 25, 5, 5);
        p.fill(0, 68, 95, ba * 0.3);
        p.ellipse(ax, by - 25, 14, 14);
      }
    }
    if (neon) {
      let ny = by + b.h * b.nY + 8;
      let pulse = Math.sin(t * 0.06 + b.nH) * 0.5 + 0.5;
      p.noStroke();
      p.fill(b.nH, 88, 96, 35 + pulse * 55);
      p.rect(b.x + 3, ny, b.nW, b.nHt, 1);
      p.fill(b.nH, 78, 96, 8 + pulse * 18);
      p.rect(b.x - 1, ny - 4, b.nW + 8, b.nHt + 8, 3);
    }
  });
}

p.draw = function() {
  let tStr = p.getSynthVar('time_of_day') || 'twilight';
  let dStr = p.getSynthVar('building_density') || 'medium';
  let det  = p.getSynthVar('rooftop_detail') || 'standard';
  let atm  = p.getSynthVar('atmosphere') || 'birds';

  if (dStr !== us.prevD) {
    us.bg = usGen(dStr, true);
    us.fg = usGen(dStr, false);
    us.prevD = dStr;
  }

  let P = usPal[tStr] || usPal.twilight;
  let t = p.frameCount;
  let gY = 340, wH = 160;
  let isNeon = tStr === 'neon';

  // ── Sky gradient (14 bands) ──
  p.noStroke();
  for (let i = 0; i < 14; i++) {
    let f = i / 14;
    p.fill(p.lerp(P.s1[0],P.s2[0],f), p.lerp(P.s1[1],P.s2[1],f), p.lerp(P.s1[2],P.s2[2],f), 100);
    p.rect(0, i * (gY / 14), 400, gY / 14 + 1);
  }

  // ── Stars ──
  if (P.star || atm === 'starry') {
    us.stars.forEach(function(st) {
      let tw = Math.sin(t * st.sp + st.ph) * 0.5 + 0.5;
      p.noStroke();
      p.fill(45, 10, 100, 16 + tw * 72);
      p.ellipse(st.x, st.y, st.s, st.s);
    });
  }

  // ── Moon ──
  if (P.moon) {
    p.noStroke();
    p.fill(45, 8, 100, 6);  p.ellipse(320, 60, 85, 85);
    p.fill(45, 8, 100, 13); p.ellipse(320, 60, 50, 50);
    p.fill(45, 10, 98, 88); p.ellipse(320, 60, 28, 28);
    p.fill(P.s1[0], P.s1[1], P.s1[2] * 0.6, 72);
    p.ellipse(326, 58, 22, 25);
  }

  // ── Clouds ──
  us.clouds.forEach(function(cl) {
    cl.x += cl.sp;
    if (cl.x > 470) cl.x = -cl.w - 30;
    let ca = P.rain ? 38 : 18;
    p.noStroke();
    p.fill(P.s1[0], P.s1[1] * 0.35, Math.min(100, P.s1[2] * 1.35), ca);
    p.ellipse(cl.x, cl.y, cl.w, cl.h);
    p.ellipse(cl.x + cl.w * 0.28, cl.y - cl.h * 0.22, cl.w * 0.6, cl.h * 0.85);
    p.ellipse(cl.x - cl.w * 0.22, cl.y + cl.h * 0.12, cl.w * 0.48, cl.h * 0.72);
  });

  // ── Background buildings ──
  usDrawB(us.bg, gY, P.bk, P.wn, det, t, false);

  // ── Foreground buildings ──
  usDrawB(us.fg, gY, P.bl, P.wn, det, t, isNeon);

  // ── Window flicker (every ~3s toggle ~4% of windows) ──
  if (t % 90 === 0) {
    [us.fg, us.bg].forEach(function(layer) {
      layer.forEach(function(b) {
        b.wins.forEach(function(w) { if (Math.random() < 0.04) w.lit = !w.lit; });
      });
    });
  }

  // ── Capture scene for water reflection ──
  let reflImg = p.get(0, 0, 400, gY);

  // ── Water base gradient ──
  p.noStroke();
  for (let i = 0; i < 8; i++) {
    let f = i / 8;
    p.fill(P.wt[0], P.wt[1], p.lerp(P.wt[2], P.wt[2] * 0.3, f), 100);
    p.rect(0, gY + i * (wH / 8), 400, wH / 8 + 1);
  }

  // ── Reflected image (flipped vertically below waterline) ──
  p.push();
  p.translate(0, gY * 2);
  p.scale(1, -1);
  p.image(reflImg, 0, 0);
  p.pop();

  // ── Water tint overlay ──
  p.noStroke();
  p.fill(P.wt[0], P.wt[1] + 5, P.wt[2], 50);
  p.rect(0, gY, 400, wH);

  // ── Ripple lines ──
  for (let ry = gY; ry < gY + wH; ry += 3) {
    let d = ry - gY;
    let ra = p.map(d, 0, wH, 2, 22);
    let xo = Math.sin(t * 0.025 + ry * 0.07) * (1 + d * 0.018);
    p.stroke(P.wt[0], P.wt[1] + 12, Math.min(100, P.wt[2] * 1.5), ra);
    p.strokeWeight(0.6);
    p.line(xo, ry, 400 + xo, ry);
  }

  // ── Light shimmer on water ──
  if (isNeon || tStr === 'golden' || tStr === 'sunset') {
    for (let i = 0; i < 10; i++) {
      let sx = p.noise(i * 3.7, t * 0.01) * 400;
      let sy = gY + p.noise(i * 5.1, t * 0.008) * wH;
      let sa = (Math.sin(t * 0.05 + i * 2.4) * 0.5 + 0.5) * 50;
      p.noStroke();
      p.fill(P.wn[0], P.wn[1] * 0.4, 100, sa);
      p.ellipse(sx, sy, 3, 1.5);
    }
  }

  // ── Shoreline highlight ──
  p.noStroke();
  p.fill(P.wt[0], P.wt[1] * 0.4, Math.min(100, P.wt[2] * 2.2), 20);
  p.rect(0, gY - 1, 400, 3);

  // ── Birds with wing flap ──
  if (atm === 'birds') {
    us.birds.forEach(function(b) {
      b.x += b.vx;
      if (b.x > 420) { b.x = -14; b.y = 18 + Math.random() * 90; }
      let wf = Math.sin(t * 0.12 + b.x * 0.1) * b.sz * 1.2;
      p.noFill();
      p.stroke(P.bl[0], P.bl[1] * 0.4, Math.min(100, P.bl[2] + 28), 52);
      p.strokeWeight(1);
      p.arc(b.x, b.y, b.sz * 3.5, b.sz * 2 + wf, p.PI, p.TWO_PI);
      p.arc(b.x + b.sz * 3.5, b.y, b.sz * 3.5, b.sz * 2 + wf, p.PI, p.TWO_PI);
    });
  }

  // ── Rain ──
  if (P.rain || atm === 'rainy') {
    p.stroke(P.s1[0], P.s1[1] * 0.4, Math.min(100, P.s1[2] + 32), 30);
    p.strokeWeight(1);
    for (let i = 0; i < 80; i++) {
      let rx = (i * 53 + t * 4.1) % 460 - 30;
      let ry = (i * 79 + t * 9) % (gY + 50);
      p.line(rx, ry, rx - 2.5, ry + 14);
    }
  }

  // ── Fog ──
  if (atm === 'foggy') {
    p.noStroke();
    for (let i = 0; i < 5; i++) {
      let fy = gY - 55 + i * 26;
      p.fill(P.s1[0], P.s1[1] * 0.28, Math.min(100, P.s1[2] * 1.18), 13);
      p.ellipse(200 + Math.sin(t * 0.008 + i) * 28, fy, 500, 65);
    }
  }
};
